          fullName: null,
          class: null,
          birthDate: null,
          passport: null,
          birthCertificate: null,
          basketPassport: null,
          phoneNum: null,
          email: null,
          vk: null,
          visa: null,
          height: null,
          category: null,
          role: null,
          check: null,
          players: [],
          prevStep: 2,
          nextStep: 4,
          checked: null,
          disable: true,
          active: false,
          gender: null,
          submitStatus: null,
          show: true,
          instructionTxt: null,
          instructionVideo: null,
          editingPlayerId: null
        }
      },
      validations() {
        if(this.is18 == 1) {
          return {
            fullName: {
              required,
              maxLength: maxLength(40),
              alpha: val => /^[а-яёА-ЯЁ ]+ [а-яёА-ЯЁ ]+ [а-яёА-ЯЁ ]+$/.test(val)
            },
            class: {
              required,
              maxLength: maxLength(2),
              numeric: val => /^([1-9]|1[0-2])$/.test(val)
            },
            birthDate: {
              required,
              numeric: val => /^([0-2]?[1-9]|[1-3][0-2])\.(0[0-9]|1[0-2])\.200[1-6]{1}$/.test(val),
            },
            passport: {
              required,
              numeric: val => /(?:[IVX]{2}|[0-9]{2})[0-9]{2}[\s\/](?:[А-Я]{2}|[0-9]{3}\s*[0-9]{3})/.test(val)
            },
            birthCertificate: {
              required,
              numeric: val => /^[0-9]+$/.test(val)
            },
            basketPassport: {
              required,
              maxLength: maxLength(10),
              numeric: val => /^[0-9]+$/.test(val)
            },
            phoneNum: {
              required,
              numeric: val => /^(\s*)?(\+)?([- _():=+]?\d[- _():=+]?){10,14}(\s*)?$/.test(val)
            },
            email: {
              required,
              email: val => /^[\w-\.]+@([\w-]+\.)+[\w-]{2,4}$/.test(val)
            },
            vk: {
              required,
              maxLength: maxLength(30),
              // alpha: val => /((\bwall|\bphoto|\bvideo|\btopic)(\-*)(\d+)_(\d+))|(club|id|public|group|board|albums|sel=[c]*)(\-*)(\d+)|(\bfriends\b|\bfeed\b|\bgroups\b|\bfave\b|\bphotos\b|\bvideos\b|\bim\b(?!\?))/.test(val)
            },
            // visa: {required},
            height: {
              required,
              minLength: minLength(3),
              numeric: val => /^[1-2][0-9][0-9]*$/.test(val)
            },
            category: {required},
            role: {required},
            check: {required}
          }
        } else {
          return {
            fullName: {
              required,
              alpha: val => /^[а-яёА-ЯЁ ]+ [а-яёА-ЯЁ ]+ [а-яёА-ЯЁ ]+$/.test(val)
            },
            birthDate: {
              required,
              numeric: val =>/^([0-2]?[1-9]|[1-3][0-2])\.(0[0-9]|1[0-2])\.200[1-6]{1}$/.test(val),
            },
            passport: {
              required,
              numeric: val => /(?:[IVX]{2}|[0-9]{2})[0-9]{2}[\s\/](?:[А-Я]{2}|[0-9]{3}\s*[0-9]{3})/.test(val)
            },
            basketPassport: {
              required,
              maxLength: maxLength(10),
              numeric: val => /^[0-9]+$/.test(val)
            },
            phoneNum: {
              required,
              numeric: val => /^(\s*)?(\+)?([- _():=+]?\d[- _():=+]?){10,14}(\s*)?$/.test(val)
            },
            email: {
              required,
               email: val => /^[\w-\.]+@([\w-]+\.)+[\w-]{2,4}$/.test(val)
            },
            vk: {
              required,
              maxLength: maxLength(30),
              // alpha: val => /((\bwall|\bphoto|\bvideo|\btopic)(\-*)(\d+)_(\d+))|(club|id|public|group|board|albums|sel=[c]*)(\-*)(\d+)|(\bfriends\b|\bfeed\b|\bgroups\b|\bfave\b|\bphotos\b|\bvideos\b|\bim\b(?!\?))/.test(val)
            },
            // visa: {required},
            height: {
              required,
              minLength: minLength(3),
              numeric: val => /^[1-2][0-9][0-9]*$/.test(val)
            },
            category: {required},
            role: {required},
            check: {required}
          }
        }
      },
      mounted() {
        if(localStorage.getItem("players")) {
            this.players = JSON.parse(localStorage.getItem("players"));
        }
        if(localStorage.getItem("CompositionPlayers")) {
          var data = JSON.parse(localStorage.getItem("CompositionPlayers"));
          this.is18 = data.is18;
          this.gender = data.gender;
        }
        if(localStorage.getItem("instructionsUrl")) {
          var instructiondata = JSON.parse(localStorage.getItem("instructionsUrl"));

          this.instructionTxt = instructiondata.txt;
          this.instructionVideo = instructiondata.video;
        }
      },
      watch: {
        players(val) {
          if(val.length >= 1) {
            this.checked = true;
          } else {
            this.checked = null;
          }

          if(val.length >= 1) {
            this.show = false;
          }
        },
        checked(val){
          if(val) {
            this.disable = false;
            this.active = true;
          } else {
            this.disable = true;
            this.active = false;
          }
        },
        gender(val) {
          if(val) {
            this.saveSelectors();
          }
        },
        is18(val) {
          if(val) {
            this.saveSelectors();
          }
        }
      },
      methods: {
        status(validation) {
          return {
            error: validation.$error,
          }
        },
        checkSubmit() {
          this.$v.$touch();
          if (this.$v.$invalid) {
            this.submitStatus = 'ERROR';
          } else if(this.check == '1') {
            this.submitStatus = 'success';
            this.submit();
          }
        },
        submit() {
            this.players.push({
              fullName: this.fullName,
              class: this.class,
              birthDate: this.birthDate,
              passport: this.passport,
              birthCertificate: this.birthCertificate,
              basketPassport: this.basketPassport,
              phoneNum: this.phoneNum,
              email: this.email,
              vk: this.vk,
              visa: this.visa,
              height: this.height,
              category: this.category,
              role: this.role,
              gender: this.gender,
            });
            setTimeout(() => {
              this.fullName = this.birthDate = this.phoneNum = this.email = this.vk = this.class =
                this.passport = this.birthCertificate = this.basketPassport = this.visa = this.height = this.check = this.category =
                this.submitStatus = this.role = null;
              this.$v.$touch();
              this.$v.$reset();
            }, 1000);

          this.savePlayers();

        },
        saveSelectors() {
          var parsed = {
            is18: this.is18,
            gender: this.gender
          };

          localStorage.setItem("CompositionPlayers", JSON.stringify(parsed));
        },
        savePlayers() {
          let parsed = JSON.stringify(this.players);
          localStorage.setItem('players', parsed);
        },
        deletePlayer(e) {
          this.players.splice(e,1);
          this.savePlayers();
        },
        editPlayer(e) {
            this.editingPlayerId = e;
            var player = this.players[e];

            this.fullName = player.fullName;
            this.class = player.class;
            this.birthDate = player.birthDate;
            this.passport = player.passport;
            this.birthCertificate = player.birthCertificate;
            this.basketPassport = player.basketPassport;
            this.phoneNum = player.phoneNum;
            this.email = player.email;
            this.vk = player.vk;
            this.height = player.height;
            this.category = player.category;
            this.role = player.role;
        },
        saveEditPlayer() {
          this.$v.$touch();
          if (this.$v.$invalid) {
            this.submitStatus = 'ERROR';
          } else if(this.check == '1') {
            this.submitStatus = 'success';
            var player = this.players[this.editingPlayerId];
            player.fullName = this.fullName;
            player.class = this.class;
            player.birthDate = this.birthDate;
            player.passport = this.passport;
            player.birthCertificate = this.birthCertificate;
            player.basketPassport = this.basketPassport;
            player.phoneNum = this.phoneNum;
            player.email = this.email;
            player.vk = this.vk;
            player.height = this.height;
            player.height = this.height;
            player.category = this.category;
            player.role = this.role;
          }

          setTimeout(() => {
            this.fullName = this.birthDate = this.phoneNum = this.email = this.vk = this.class =
              this.passport = this.birthCertificate = this.basketPassport = this.visa = this.height = this.check = this.category =
                this.submitStatus = this.role = null;
            this.$v.$touch();
            this.$v.$reset();
          }, 1000);

          this.savePlayers();
        },
        prevPage() {this.Players(this.prevStep)},
        nextPage() {
          if(this.players.length >= 1) {
            this.Players(this.nextStep)
          }
        },
      }
    }
</script>

<style scoped>
  /*.card-body {*/
    /*min-height: 651px;*/
  /*}*/
  .fade-enter-active, .fade-leave-active {
    transition: opacity .5s;
  }
  .fade-enter, .fade-leave-to /* .fade-leave-active до версии 2.1.8 */ {
    opacity: 0;
  }
  .error {
    border-color: red !important;
    background: #FDD !important;
  }

  .card-EventList {
    align-items: center;
    padding-left: 100px;
    padding-right: 100px;
    padding-top: 60px;
    min-height: 0!important;
  }

  .card-EventList #addPlayer {
    margin-top: 30px;
    width: 100%;
    height: 60px;
    color: #FFFFFF;
    padding-top: 19px;
    margin-top: 30px;
    margin-bottom: 60px;
    font: normal normal 600 18px Gilroy;
    background: #F5AC3B;
  }

  .uk-modal-header {
    padding-top: 60px;
    padding-bottom: 60px;
    text-align: center;
    border: none;
  }

  .uk-modal-body {
    padding-left: 100px;
    padding-right: 100px;
  }

  .uk-modal-title {
    font: normal normal bold 40px/70px Gilroy;
  }

  input {
    margin-bottom: 0;
  }

  p {
    font: normal normal 600 22px/27px Gilroy;
    color: #000000;
  }

  #modalPlayer select,  #modalEditPlayer select{
    width: 100%;
    height: 60px;
    margin-top: 30px;
    background: #F9F9F9;
    border: 1px solid #DBDBDB;
    border-radius: 3px;
    font: normal normal normal 18px/28px Gilroy;
    color: #A3A6B4;
    outline: none;
  }

  #modalPlayer button, #modalEditPlayer button {
    width: 100%;
    height: 60px;
    color: #FFFFFF;
    border-radius: 3px !important;
    font: normal normal 600 18px Gilroy;
    background: #F5AC3B;
  }

  .playersTable {
    border: 1px solid #DBDBDB;
  }

  .playersTable td{
    font: normal normal normal 18px/28px Gilroy;
    color: #000000;
  }

  .playersTable .index {
    width: 60px;
    height: 60px;
    text-align: center;
  }

  .playersTable .fullName {
    padding-left: 20px;
    width: 445px;
  }

  .playersTable .birthDay {
    text-align: center;
    width: 117px;
  }

  .playersTable .Height {
    text-align: center;
    width: 90px;
  }

  .playersTable .PlayerRole {
    text-align: center;
    width: 197px;
  }

  .playersTable .menu {
    width: 61px;
  }

  .menu button {
    border: none;
    margin: 0;
    padding: 0;
    width: 61px;
    font-weight: bold;
    font-size: 20px;
    letter-spacing: 2px;
    text-align: center;
  }

  td {
    border: 1px solid #DBDBDB;
    padding: 0;
    margin: 0;
  }

  input[type="text"], input[type="tel"] {
    margin-top: 30px;
  }

</style>



