import Vue from 'vue'
import App from './App.vue'
import Vuelidate from 'vuelidate'
import Vuex from 'vuex'
import VueTheMask from 'vue-the-mask'



Vue.use(Vuelidate, Vuex, VueTheMask);
Vue.config.productionTip = false;
new Vue({
  el: '#app',
  render: h => h(App)
});





