<template>
  <div class="uk-section" style="padding: 0;">
    <div id="modal-video" class="uk-flex-top" uk-modal>
      <div class="uk-modal-dialog uk-width-auto uk-margin-auto-vertical">
        <button class="uk-modal-close-outside" type="button" uk-close></button>
        <video :src="instructionVideo" controls playsinline uk-video></video>
      </div>
    </div>
    <div id="error-modal" class="uk-flex-top" uk-modal>
      <div class="uk-modal-dialog uk-modal-body uk-margin-auto-vertical">

        <button class="uk-modal-close-default" type="button" uk-close></button>
        <p>В данном мероприятии нет видео инструкции и текстовой инстукции</p>

      </div>
    </div>
    <div id="center-container" style="max-width:1400px;;margin: 0 auto" uk-grid>
      <div id="left-panel" class="uk-width-expand@m" style="padding: 0">
        <div class="uk-container" style="padding: 0; margin: 0;">
          <div class="card-header uk-flex">
            <div class="circle">
              <img src="../../assets/checked.png" style="width: 20px;">
            </div>
            <p class="circle-text">Шаг 1</p>
            <hr>
            <div class="circle"></div>
            <p class="circle-text">Шаг 2</p>
            <hr>
            <div class="circle circle-hidden"></div>
            <p class="circle-text circle-text-hidden">Шаг 3</p>
            <hr>
            <div class="circle circle-hidden"></div>
            <p class="circle-text circle-text-hidden">Шаг 4</p>
          </div>
          <div class="card-progressbar">
            <span class="progress" style="width: calc(100% / 2);"></span>
          </div>
          <div class="card-body">
            <div class="card-EventList" style="text-align: center; align-items: center; justify-content: center; display: flex; min-height: 156px;">
              <div class="card-EventListBody">
                <p style="font: normal 27px Gilroy; color: #000000; font-weight: 600; margin: 0;">Кубок мэра республики Башкортостан</p>
              </div>
            </div>
            <div class="card-EventList">
              <div class="card-EventListBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Выберите муниципалитет из списка</p>
                <select name="Municipality" v-model="$v.municipality.$model" @blur.prevent="$v.municipality.$touch()" :class="status($v.municipality)">
                  <option v-for="l in list[0]">{{ l.name }}</option>
                </select>
              </div>
            </div>
            <!--<div class="card-EventList">-->
              <!--<div class="card-EventListBody">-->
                <!--<p style="font: normal normal 600 22px/27px Gilroy;">Выберите район из списка</p>-->
                <!--<select name="Area" v-model="$v.district.$model" @blur.prevent="$v.district.$touch()" :class="status($v.district)">-->
                  <!--<option v-for="l in listDist[0]">{{ l.name }}</option>-->
                <!--</select>-->
              <!--</div>-->
            <!--</div>-->
            <div class="card-EventList">
              <div class="card-EventListBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Выберите вид населенного пункта из списка</p>
                <select name="locationType" v-model="$v.locationType.$model" @blur.prevent="$v.locationType.$touch()" :class="status($v.locationType)">
                  <option>Вид населенного пункта</option>
                  <option v-for="l in LocationTypeData[0]">{{ l.name }}</option>
                </select>
              </div>
            </div>
            <div class="card-EventList">
              <div class="card-EventListBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Укажите название населенного пункта</p>
                <input type="text" class="uk-input" placeholder="Название населенного пункта" name="locationName" v-model="$v.locationName.$model" @blur.prevent="$v.locationName.$touch()" :class="status($v.locationName)">
              </div>
            </div>
            <div class="card-EventList">
              <div class="card-EventListBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Укажите полное название организации</p>
                <input type="text" class="uk-input" placeholder="Полное название организации" name="fullName" v-model="$v.fullName.$model" @blur.prevent="$v.fullName.$touch()" :class="status($v.fullName)">
              </div>
            </div>
            <div class="card-EventList">
              <div class="card-EventListBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Укажите краткое название организации</p>
                <input type="text" class="uk-input" placeholder="Краткое название организации" name="shortName" v-model="$v.shortName.$model" @blur.prevent="$v.shortName.$touch()" :class="status($v.shortName)">
              </div>
            </div>
            <div class="card-EventList">
              <div class="card-EventListBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Укажите название команды</p>
                <input type="text" class="uk-input" placeholder="Название команды" name="CommandName" v-model="$v.teamName.$model" @blur.prevent="$v.teamName.$touch()" :class="status($v.teamName)">
              </div>
            </div>
          </div>
        </div>
        <div class="uk-container" style="height: 100px; padding: 0;">
          <div class="uk-flex-between uk-flex">
            <button @click.prevent="prevPage" style="background: #A3A6B4;">
              <img src="../../assets/left-arrow.png" style="width: 17px;">
              Назад</button>
            <button @click.prevent="checkInputs" :disabled="submitStatus === 'success'" v-bind:class="{ 'button-disable': this.$v.$invalid, 'button-success': !this.$v.$invalid }">Далее
              <img src="../../assets/right-arrow.png" style="width: 17px;">
            </button>
          </div>
        </div>
      </div>
      <div id="right-panel" class="uk-width-auto@l" style="padding:0;">

        <div style="width:100px;height:100px">

          <div class="uk-visible@m">
            <div style="position: fixed;width:67px;height:100px;">
              <a v-if="instructionTxt != null" :href="instructionTxt" target="_blank" class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy;">Инструкция</p>

              <a v-if="instructionVideo != null" href="#modal-video" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy; text-align: center;">Видео <br> инструкция</p>
            </div>
          </div>

          <div class="uk-hidden@m uk-flex">
            <div style="margin-left: 55px;">
              <a v-if="instructionTxt != null" :href="instructionTxt" target="_blank" class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy;">Инструкция</p>

              <a v-if="instructionVideo != null" href="#modal-video" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy; text-align: center;">Видео <br> инструкция</p>
            </div>
          </div>

        </div>

      </div>
    </div>
  </div>
</template>

<script>

  import {HTTP} from '../../http.js';
  import { required } from 'vuelidate/lib/validators';
  export default {
    name: "InfoOrgArea",
    props: ['InfoOrgArea'],
    data() {
      return {
        eventType: 2,
        municipality: null,
        // district: null,
        locationType: null,
        locationName: null,
        fullName: null,
        shortName: null,
        teamName: null,
        errors: [],
        checked: [],
        prevStep: 1,
        nextStep: 3,
        active: false,
        disable: true,
        getMunicipal: [],
        list: [],
        getLocation: [],
        LocationTypeData: [],
        submitStatus: null,
        instructionTxt: null,
        instructionVideo: null,
      }
    },
    validations: {
      municipality: {required},
      locationType: {required},
      locationName: {
        required,
        alpha: val => /^[а-яёА-ЯЁ ]+$/.test(val)
      },
      fullName: {
        required,
        alpha: val => /^[а-яёА-ЯЁ ]+$/.test(val)
      },
      shortName: {
        required,
        alpha: val => /^[а-яёА-ЯЁ ]+$/.test(val)
      },
      teamName: {
        required,
        alpha: val => /^[а-яёА-ЯЁ ]+$/.test(val)
      },
    },
    mounted() {
      if(localStorage.getItem("InfoOrgArea")) {
        var data = JSON.parse(localStorage.getItem("InfoOrgArea"));
        this.municipality = data.InfoOrg.municipality;
        // this.district = data.InfoOrgArea.district;
        this.locationType = data.InfoOrg.locationType;
        this.locationName = data.InfoOrg.locationName;
        this.shortName = data.InfoOrg.shortName;
        this.fullName = data.InfoOrg.fullName;
        this.teamName = data.InfoOrg.teamName;
      }

      if(localStorage.getItem("instructionsUrl")) {
        var instructiondata = JSON.parse(localStorage.getItem("instructionsUrl"));

        this.instructionTxt = instructiondata.txt;
        this.instructionVideo = instructiondata.video;
      }

      localStorage.removeItem("InfoOrg");
      this.getMunicipality();
      // this.getDistrict(this.districtUrl);
      this.getLocationType();
    },
    methods: {
      checkInputs() {
        this.$v.$touch();
        if (!this.$v.$invalid) {
          this.submitStatus = 'success';
          this.submit();
        }
      },
      getMunicipality() {
        // const data = [];
        HTTP.head("/api/municipal-districts")
          .then(response => (this.getMunicipal.push(response)));
      },
      getLocationType() {
        HTTP.get("/api/location")
          .then(response => (this.getLocation.push(response)));
      },
      submit() {
        let data = {
          InfoOrg: {
            municipality: this.municipality,
            district: this.district,
            locationType: this.locationType,
            locationName: this.locationName,
            fullName: this.fullName,
            shortName: this.shortName,
            teamName: this.teamName
          }
        };
        this.selectEvent();
        localStorage.setItem('InfoOrgArea', JSON.stringify(data));
      },
      status(validation) {
        return {
          error: validation.$error
        }
      },
      prevPage() {this.InfoOrgArea(this.prevStep)},
      selectEvent() {this.InfoOrgArea(this.nextStep);},
    },
    watch: {
      getMunicipal(val) {
        Object.keys(val).forEach(key => {
          this.list = val[key].data;
        });
      },
      // getDistrictData(val) {
      //   Object.keys(val).forEach(key => {
      //     this.listDist = val[key].data;
      //   });
      // },
      getLocation(val) {
        Object.keys(val).forEach(key => {
          this.LocationTypeData = val[key].data;
        });
      }
    },
  }
</script>

<style scoped>
  .card-body {
    height: 1584px;
  }
  .error {
    border-color: red !important;
    background: #FDD !important;
  }
</style>



