<template>
  <div class="uk-section" style="padding: 0;">
    <div id="modal-media-video" class="uk-flex-top" uk-modal>
      <div class="uk-modal-dialog uk-width-auto uk-margin-auto-vertical">
        <button class="uk-modal-close-outside" type="button" uk-close></button>
        <video :src="instructionVideo" controls playsinline uk-video></video>
      </div>
    </div>
    <div id="error-modal" class="uk-flex-top" uk-modal>
      <div class="uk-modal-dialog uk-modal-body uk-margin-auto-vertical">

        <button class="uk-modal-close-default" type="button" uk-close></button>

        <p v-if="this.eventName === null">Для начала выберите мероприятие</p>
        <p v-else>В данном мероприятии нет видео инструкции и текстовой инстукции</p>

      </div>
    </div>
    <div id="center-container" style="max-width:1400px ;margin: 0 auto;" uk-grid>
      <div id="left-panel" class="uk-width-expand@m" style="padding: 0;">
        <div class="uk-container" style="padding: 0; margin: 0;">
          <div class="card-header uk-flex">
            <div class="circle"></div>
            <p class="circle-text">Шаг 1</p>
            <hr>
            <div class="circle circle-hidden"></div>
            <p class="circle-text circle-text-hidden">Шаг 2</p>
            <hr>
            <div class="circle circle-hidden"></div>
            <p class="circle-text circle-text-hidden">Шаг 3</p>
            <hr>
            <div class="circle circle-hidden"></div>
            <p class="circle-text circle-text-hidden">Шаг 4</p>
          </div>
          <div class="card-progressbar">
            <span class="progress" style="width: calc(100% / 4);"></span>
          </div>
          <div class="card-body">
            <div class="card-eventType">
              <div class="card-eventTypeBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Укажите тип мероприятия</p>
                <div class="form-eventType">
                  <input type="radio" id="municipal" name="Event" ref="Event" value="1" @click="getEventName(1)" v-model="$v.eventType.$model" @blur.prevent="$v.eventType.$touch()" :class="status($v.eventType)">
                  <label for="municipal">Городское</label>
                  <input type="radio" id="District" name="Event" ref="Event" value="2" @click="getEventName(2)" style="margin-left: 60px;" v-model="$v.eventType.$model" @blur.prevent="$v.eventType.$touch()" :class="status($v.eventType)">
                  <label for="District">Районное</label>
                </div>
              </div>
            </div>
            <div class="card-EventList">
              <div class="card-EventListBody">
                <p style="font: normal normal 600 22px/27px Gilroy;">Выберите мероприятие из списка</p>
                <select v-model="$v.eventName.$model" @blur.prevent="$v.eventName.$touch()" :class="status($v.eventName)">
                  <option disabled>Список мероприятий</option>
                  <option v-for="l in list" :value="{id: l.id, name: l.name}">{{ l.name }}</option>
                </select>
              </div>
            </div>
          </div>
        </div>
        <div class="uk-container" style="padding: 0">
          <div class="uk-flex-right uk-flex" style="height: 45px;">
            <button @click.prevent="checkInputs" :disabled="submitStatus === 'success'" v-bind:class="{ 'button-disable': disable, 'button-success': active }">Далее
              <img src="../../assets/right-arrow.png" style="width: 17px;">
            </button>
          </div>
        </div>
      </div>
      <div id="right-panel" class="uk-width-auto@l" style="padding:0;">
        <div style="width:100px;height:100px">

          <div class="uk-visible@m">
            <div style="position: fixed;width:67px;height:100px;">
              <a v-if="instructionTxt != null" :href="instructionTxt" target="_blank" class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy;">Инструкция</p>

              <a v-if="instructionVideo != null" href="#modal-media-video" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy; text-align: center;">Видео <br> инструкция</p>
            </div>
          </div>

          <div class="uk-hidden@m uk-flex">
            <div style="margin-left: 55px;">
              <a v-if="instructionTxt != null" :href="instructionTxt" target="_blank" class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/settings.svg">
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy;">Инструкция</p>

              <a v-if="instructionVideo != null" href="#modal-video" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <a v-else href="#error-modal" uk-toggle class="circle" style="background: #A3A6B4; padding: 0 !important; margin: 0 auto;">
                <img src="../../assets/play.svg" style="padding: 16px 15px 16px 21px;">
                <!--<img data-src="../../assets/settings.svg" style="width:28px; height: 28px;" alt="" uk-img>-->
              </a>
              <p style="padding: 0; margin-top: 15px; font: normal normal 600 12px/14px Gilroy; text-align: center;">Видео <br> инструкция</p>
            </div>
          </div>

        </div>

      </div>
    </div>

    </div>
</template>

<script>
  import {HTTP} from '../../http.js';
  import { required } from 'vuelidate/lib/validators';
  export default {
    name: "SelectEvent",
    props: ['checkSelectEvent'],
    data() {
      return {
        eventType: null,
        eventName: null,
        checked: null,
        nextStep: 2,
        active: false,
        disable: true,
        getList: [],
        list: null,
        id: null,
        submitStatus: 'ERROR',
        instructionTxt: null,
        instructionVideo: null,
      }
    },
    validations: {
      eventType: {required},
      eventName: {required},
    },
    mounted() {
      if(localStorage.getItem("SelectEvent")) {
        let data = JSON.parse(localStorage.getItem("SelectEvent"));
        this.eventType = data.SelectEvent.eventType;
        this.eventName = data.SelectEvent.eventName;
      }
    },
    methods: {
      checkInputs() {
        this.$v.$touch();
        if(this.$v.$invalid && this.eventName != 'Список мероприятий') {
          this.disable = true;
          this.active = false;
        } else {
          this.disable = true;
          this.active = false;
          this.submitStatus = 'success';
          this.save();
          this.selectEvent();
        }
      },
      selectEvent() {this.checkSelectEvent({step: this.nextStep, eventType: this.eventType});},
      save() {
        let data = {
          SelectEvent: {
            eventType: this.eventType,
            eventName: this.eventName
          }
        };
        localStorage.setItem('SelectEvent', JSON.stringify(data));
      },
      status(validation) {
        return {
          error: validation.$error
        }
      },
      getEventName(val) {
        this.eventName = null;

        HTTP.post("/api/campaign/get", {type: val})
            .then(response => (this.getList.push(response)));

       // axios.post(nodevn.BASE_URL+"/api/campaign/get", {type: val})
       //    .then(response => (this.getList.push(response)));
      },
      setInstructionUrl(response) {

        this.instructionTxt = nodevn.BASE_URL + /assets/ + response.data[0].instruction;
        this.instructionVideo = nodevn.BASE_URL + /assets/ + response.data[0].video;
        if(response.data[0].instruction === null) {
          this.instructionTxt = null;
        }
        if(response.data[0].video === null) {
          this.instructionVideo = null;
        }
        if(response.data[0].instruction != null ||response.data[0].video != null) {

          var data = {
            "txt": this.instructionTxt,
            "video": this.instructionVideo
          };

          localStorage.setItem("instructionsUrl", JSON.stringify(data));
        }
      }
    },
    watch: {
      eventType(val) {
        this.instructionTxt = null;
        this.instructionVideo = null;
        localStorage.removeItem("instructionsUrl");
        HTTP.post("/api/campaign/get", {type: val})
          .then(response => (this.getList.push(response)));
      },
      eventName(val) {
        if(val != "Список мероприятий" && val) {
          this.checked = true;
          HTTP.post("/api/campaign-files/" + val.id)
            .then(response => (this.setInstructionUrl(response)));
        } else {
          this.checked = false;
        }
      },
      checked(val){
        if(val) {
          this.disable = false;
          this.active = true;
        } else {
          this.active = false;
          this.disable = true;
        }
      },
      getList(val) {
        Object.keys(val).forEach(key => {
          this.list = val[key].data;
        })
      }
    },
  }
</script>

<style scoped>

  .error {
    border-color: red !important;
    background: #FDD !important;
  }

</style>



