<template>
  <div id="app" style="margin: 0">
    <Navbar></Navbar>
    <div class="uk-section" v-if="step != 5">
        <div class="uk-container" id="progress-container" style="padding: 0; margin: 0 auto;">
          <div class="progress-header uk-flex-between uk-flex" style="max-width: 1170px; margin: 0 auto;">
            <div class="progress-header-left uk-flex" style="align-items: center;">
              <div class="circle">
                <p style="font: normal normal bold 30px/70px Gilroy;">{{ step }}</p>
              </div>
              <div class="uk-text-center uk-flex" style="align-items: center;">
                <p style="margin: 0; margin-left: 40px; font: normal normal bold 40px Gilroy; color: #000000;" v-if="step == 1">Выбор мероприятия</p>
                <p style="margin: 0; margin-left: 40px; font: normal normal bold 40px Gilroy; color: #000000;" v-if="step == 2">Информация об организации</p>
                <p style="margin: 0; margin-left: 40px; font: normal normal bold 40px Gilroy; color: #000000;" v-if="step == 3">Состав игроков</p>
                <p style="margin: 0; margin-left: 40px; font: normal normal bold 40px Gilroy; color: #000000;" v-if="step == 4">Сопровождающие</p>
              </div>
            </div>
            <div class="progress-header-right uk-flex" style="align-items: center; font: normal normal bold 40px/70px Gilroy; color: #A3A6B4;">
              <p style="margin: 0; font: normal normal bold 40px/70px Gilroy;">шаг {{ step }} из 4</p>
            </div>
          </div>
        </div>
    </div>
    <form id="form">
      <SelectEvent :checkSelectEvent="checkSelectEvent" v-if="step == 1"></SelectEvent>
      <InfoOrg :InfoOrg="InfoOrg" v-if="step == 2 && EventType == '1'"></InfoOrg>
      <InfoOrgArea :InfoOrgArea="InfoOrgArea"  v-if="step == 2 && EventType == '2'"></InfoOrgArea>
      <Players :Players="Players" v-if="step == 3"></Players>
      <Accompanying :Accompanying="Accompanying" v-if="step == 4"></Accompanying>
      <Success v-if="step == 5"></Success>
    </form>
  </div>
</template>

<script>
import Navbar from "./components/Navbar";
import SelectEvent from "./components/forms/SelectEvent";
import InfoOrg from "./components/forms/InfoOrg";
import InfoOrgArea from "./components/forms/InfoOrgArea";
import Players from "./components/forms/Players";
import Accompanying from "./components/forms/Accompanying";
import Success from "./components/forms/Success";
import {HTTP} from "./http.js";

export default {
  name: 'app',
  components: {
    Navbar, SelectEvent, InfoOrg,
    Players, Accompanying, Success,
    InfoOrgArea
  },
  data() {
    return {
      EventType: null,
      Type: 1,
      // totalSteps: 4,
      step: 1,
      response: [],
    }
  },
  beforeMount: function () {
    localStorage.clear();
  },
  mounted: function () {
      this.$nextTick(function () {
        document.getElementById("form").reset();
    })
  },
  methods: {
      checkSelectEvent(data) {
        this.step = data.step;
        this.EventType = data.eventType;
      },
      InfoOrg(data) {
        this.step = data;
      },
      InfoOrgArea(data) {
        this.step = data;
      },
      Players(data) {
        this.step = data;
      },
      Accompanying(data) {
        this.step = data;
      },
      sendAjax() {
        var event = JSON.parse(localStorage.getItem("SelectEvent"));

        if(JSON.parse(localStorage.getItem("InfoOrg"))) {
          var info = JSON.parse(localStorage.getItem("InfoOrg"))
        } else if(JSON.parse(localStorage.getItem("InfoOrgArea"))) {
          var info = JSON.parse(localStorage.getItem("InfoOrgArea"));
        }
        var players = JSON.parse(localStorage.getItem("players"));
        var compplayer = JSON.parse(localStorage.getItem("CompositionPlayers"));
        var accompanying = JSON.parse(localStorage.getItem("AccompanyingPeople"));

        var data = {
          event,
          info,
          players,
          accompanying,
          compplayer
        };

        HTTP.post("/api/application/form", data);

        localStorage.clear();
      }
  },
  watch: {
    step(val) {
      if(val === 5) {
        this.sendAjax();
      }
    }
  }

}
</script>

