    color: #FFFFFF;
    background: #E2E2E2;
    border-radius: 25px;
    outline: none;
    border: none;
    width: 126px;
    height: 50px;
    margin-top: 30px;
    margin-bottom: 120px;
    font: normal normal 600 18px/22px Gilroy;
  }

