    background: #F5AC3B !important;
  }

  .circle {
    width: 60px;
    height: 60px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #F5AC3B 0% 0% no-repeat padding-box;
    opacity: 1;
  }

  .circle p {
    margin-top: 25px;
    font: normal normal bold 30px/70px Gilroy;
    letter-spacing: 0px;
    color: #FFFFFF;
    opacity: 1;
    text-align: center;
  }

  .card-header > hr {
    border: 1px solid #A3A6B4;
    width: 20px;
    margin-left: 15px;
    margin-right: 15px;
  }

  .card-header {
    justify-content: center;
    align-items: center;
    background: #f9f9f9;
    border-top-left-radius: 10px;
    border-top-right-radius: 10px;
    border: 1px solid #DBDBDB;
    height: 82px;
  }

  .card-header p {
    font: normal normal 600 18px/22px Gilroy;
    margin-left: 15px;
  }

  .card-header > .circle {
    width: 30px;
    height: 30px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #F5AC3B 0% 0% no-repeat padding-box;
    opacity: 1;
  }

  .circle-hidden {
    background: #EDEDED 0% 0% no-repeat padding-box !important;
  }

  .circle-text {
    font: normal normal 600 18px/22px Gilroy;
  }

  .circle-text-hidden {
    color: #A3A6B4 !important;
  }

  .card-progressbar {
    position: relative;
    height: 20px;
    border-right: 1px solid #DBDBDB;
  }

  .card-progressbar > span {
    display: block;
    height: 100%;
    background-color: #F5AC3B;
  }

  .card-progressbar > span:after {
    content: "";
    position: absolute;
    top: 0; left: 0; bottom: 0; right: 0;
    background-image: linear-gradient(
        -45deg,
        rgba(255,255,255, 0.9) 25%,
        transparent 25%,
        transparent 45%,
        rgba(255,255,255, 0.9) 55%,
        rgba(255,255,255, 0.9) 75%,
        transparent 75%,
