    animation: move 2s linear infinite;
    overflow: hidden;
  }

  @keyframes move {
    0% {
      background-position: 0 0;
    }
    100% {
      background-position: 50px 50px;
    }
  }

  .card-body {
    border: 1px solid #DBDBDB;
