  }

  .card-eventTypeBody {
    margin-top: 60px;
  }

  .card-eventType p {
    text-align: left;
  }

  .form-eventType {
    font: normal normal 600 22px/28px Gilroy;
    display: flex;
    height: 30px;
    margin-top: 30px;
  }

  .form-eventType label{
    margin-left: 15px;
  }

   input[type="radio"] {
    width: 30px;
    height: 30px;
    margin: 0;
    border: 2px solid #E8E9EC;
    -webkit-appearance: none;
    border-radius: 50%;
    outline: none;
  }


  input[type='radio']:before {
    content: '';
    display: block;
