                      <label for="accept" style="margin-left: 15px; padding: 0;">Я согласен на обработку персональных данных</label>
                    </div>

                    <div class="uk-flex" style="justify-content: center; padding: 0; align-items: center; margin-top: 40px;">
                      <button class="uk-button uk-button-default" :class="{'uk-modal-close': submitStatus === 'success'}" :disabled="submitStatus === 'success'"  @click.prevent="checkSubmit">Добавить сопровождающего</button>
                    </div>
                  </div>
                </div>
              </form>
            </div>
          </div>
        </div>
        <div class="uk-container" style="padding: 0;">
          <div class="uk-flex-between uk-flex" style="height: 100px;">
            <button @click.prevent="prevPage" style="background: #A3A6B4;">
