<script>
  import { required, maxLength } from 'vuelidate/lib/validators';
  import {mask} from 'vue-the-mask';
    export default {
      name: "Accompanying",
      props: ["Accompanying"],
      directives: {mask},
      data() {
        return {
          errors: [],
          fullName: null,
          experience: null,
          birthDate: null,
          position: null,
          phoneNum: null,
          email: null,
          fkTeacher: null,
          workplace: null,
          standing: null,
          education: null,
          active: false,
          disable: true,
          check: null,
          submitStatus: '',
          prevStep: 3,
          nextStep: 5,
          AccompanyingPeople: [],
          show: false,
          checked: false,
          instructionTxt: null,
          instructionVideo: null,
        }
      },
      validations: {
        fullName: {
          required,
          maxLength: maxLength(40),
          alpha: val => /^[а-яёА-ЯЁ ]+ [а-яёА-ЯЁ ]+ [а-яёА-ЯЁ ]+$/.test(val)
        },
        experience: {
          required,
          maxLength: maxLength(2),
          numeric: val => /^[0-9]+$/.test(val)
        },
        birthDate: {
          required,
          // numeric: val => /^(((0[1-9]|1[012]).(0[1-9]|1\d|2[0-8])|(0[13456789]|1[012]).(29|30)|(0[13578]|1[02]).31).[2-9]\d{3}|02.29.(([2-9]\d)(0[48]|[2468][048]|[13579][26])|(([2468][048]|[3579][26])00)))$/.test(val),
        },
        position: {
          required,
          // maxLength: maxLength(50),
          // alpha: val => /^[А-ЯЁ ]+$/.test(val),
        },
        phoneNum: {
          required,
          numeric: val => /^(\s*)?(\+)?([- _():=+]?\d[- _():=+]?){10,14}(\s*)?$/.test(val)
        },
        email: {
          required,
          email: val => /^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,24}))$/.test(val)
        },
        fkTeacher: {required},
        workplace: {
          required,
          maxLength: maxLength(255),
          alpha: val => /^[а-яёА-ЯЁ ]+$/.test(val),
        },
        standing: {
          required,
          maxLength: maxLength(255),
          alpha: val => /([а-яёА-ЯЁ ]+[\-\s]?){3,}/.test(val),
        },
        education: {
          required,
          maxLength: maxLength(255),
          alpha: val => /([а-яёА-ЯЁ ]+[\-\s]?){3,}/.test(val),
        },
        check: {required}
      },
      mounted() {
        if(localStorage.getItem("AccompanyingPeople")) {
          this.AccompanyingPeople = JSON.parse(localStorage.getItem("AccompanyingPeople"));
        }

        if(localStorage.getItem("instructionsUrl")) {
          var instructiondata = JSON.parse(localStorage.getItem("instructionsUrl"));

          this.instructionTxt = instructiondata.txt;
          this.instructionVideo = instructiondata.video;
        }
      },
      watch: {
        AccompanyingPeople(val) {
          if(val.length >= 1) {
            this.checked = true;
          } else {
            this.checked = null;
          }
        },
        checked(val){
          if(val) {
            this.disable = false;
            this.active = true;
          } else {
            this.disable = true;
            this.active = false;
          }
        },
      },
      methods: {
        checkSubmit() {
          this.$v.$touch();
          if (this.$v.$invalid) {
            this.submitStatus = 'ERROR';
          } else if(this.check == '1') {
            this.submitStatus = 'success';
            this.submit();
          }
        },
        submit() {
            this.AccompanyingPeople.push({
              fullName: this.fullName,
              birthDate: this.birthDate,
              phoneNum: this.phoneNum,
              email: this.email,
              experience: this.experience,
              position: this.position,
              fkTeacher: this.fkTeacher,
              workplace: this.workplace,
              experience: this.experience,
              education: this.education,
              standing: this.standing
            });
            localStorage.setItem('AccompanyingPeople', JSON.stringify(this.AccompanyingPeople));

            setTimeout(() => {
              this.fullName = this.birthDate = this.phoneNum = this.email = this.experience = this.position =
                this.fkTeacher = this.workplace = this.experience = this.education = this.check = this.submitStatus = null;
              this.$v.$touch();
              this.$v.$reset();
            }, 1000);
        },
        deleteAccompanying(e) {
          this.AccompanyingPeople.splice(e,1);
          localStorage.setItem('AccompanyingPeople', JSON.stringify(this.AccompanyingPeople));
        },
        savePlayers() {
          let parsed = JSON.stringify(this.AccompanyingPeople);
          localStorage.setItem('AccompanyingPeople', parsed);
        },
        status(validation) {
          return {
            error: validation.$error,
          }
        },
        prevPage() {this.Accompanying(this.prevStep)},
        send() {this.Accompanying(this.nextStep)}
      }
    }
</script>

