    width: 445px;
  }

  .AccompanyingTable .birthDay {
    text-align: center;
    width: 117px;
  }

  .AccompanyingTable .position {
    text-align: center;
    width: 287px;
  }

  .playersTable .menu {
    width: 61px;
  }

  .menu button {
    border: none;
    margin: 0;
    padding: 0;
    width: 61px;
    font-weight: bold;
    font-size: 20px;
    letter-spacing: 2px;
    text-align: center;
  }

  td {
    border: 1px solid #DBDBDB;
    padding: 0;
    margin: 0;
  }

</style>



